import{_ as e,o as a,c as t,O as i}from"./chunks/framework.bdcb0ee1.js";const m=JSON.parse('{"title":"Help Pages","description":"","frontmatter":{},"headers":[],"relativePath":"administration/content/help-pages.md","filePath":"administration/content/help-pages.md","lastUpdated":1773166927000}'),n={name:"administration/content/help-pages.md"},r=i('<h1 id="help-pages" tabindex="-1">Help Pages <a class="header-anchor" href="#help-pages" aria-label="Permalink to &quot;Help Pages&quot;">​</a></h1><p>Help pages provide a built-in documentation area for your board. Use them to answer common questions, explain board rules or provide guidance for new members. You can manage them under the <strong>Content</strong> navigation group in the Admin CP.</p><nav class="table-of-contents"><ul><li><a href="#creating-a-help-page">Creating a help page</a></li><li><a href="#publishing">Publishing</a></li><li><a href="#ordering">Ordering</a></li><li><a href="#editing-and-deleting-help-pages">Editing and deleting help pages</a></li></ul></nav><h2 id="creating-a-help-page" tabindex="-1">Creating a help page <a class="header-anchor" href="#creating-a-help-page" aria-label="Permalink to &quot;Creating a help page&quot;">​</a></h2><p>Click <strong>Create Help Page</strong> to add a new entry. Each help page has the following fields:</p><ul><li><strong>Title</strong> — the page heading displayed in the help section.</li><li><strong>Slug</strong> — the URL-friendly identifier (letters, numbers, dashes and underscores only). Must be unique.</li><li><strong>Description</strong> — an optional short summary shown in the help page listing.</li><li><strong>Content</strong> — the body of the help page, written in BBCode. Supports up to 60,000 characters.</li><li><strong>Sort Order</strong> — controls the display order in the help section.</li></ul><img width="1936" height="1139" alt="image" src="https://github.com/user-attachments/assets/8d8800c5-18ec-440a-bfe1-127d695f3173"><h2 id="publishing" tabindex="-1">Publishing <a class="header-anchor" href="#publishing" aria-label="Permalink to &quot;Publishing&quot;">​</a></h2><p>Help pages support a <strong>Published</strong> status. Only published pages are visible to users in the help section. Toggle the published checkbox when creating or editing a help page to control its visibility.</p><h2 id="ordering" tabindex="-1">Ordering <a class="header-anchor" href="#ordering" aria-label="Permalink to &quot;Ordering&quot;">​</a></h2><p>Help pages are displayed in ascending order based on the <strong>Sort Order</strong> field. Use this to arrange your help content in a logical sequence, placing the most important topics first.</p><h2 id="editing-and-deleting-help-pages" tabindex="-1">Editing and deleting help pages <a class="header-anchor" href="#editing-and-deleting-help-pages" aria-label="Permalink to &quot;Editing and deleting help pages&quot;">​</a></h2><p>Click on any help page in the list to edit it. All fields can be updated at any time. To remove a help page, use the delete option — this action cannot be undone.</p>',13),o=[r];function s(l,p,h,g,d,c){return a(),t("div",null,o)}const b=e(n,[["render",s]]);export{m as __pageData,b as default};
